// audio --------------------------
#define AUDIO_BASE 0xFF203040
volatile int *audio_ptr = (int *) AUDIO_BASE;

int  *clip_data = 0;
int   clip_len  = 0;
int   clip_pos  = -1;

void trigger_clip(int *data, int len) {
    clip_data = data;
    clip_len  = len;
    clip_pos  = 0;
}

void update_audio(void) {
    if (clip_pos < 0 || clip_pos >= clip_len) {
        clip_pos = -1;
        return;
    }
    int fifospace = *(audio_ptr + 1);
    int wslc = (fifospace >> 24) & 0xFF;
    if (wslc == 0) return;

    int sample = clip_data[clip_pos++];
    *(audio_ptr + 2) = sample;
    *(audio_ptr + 3) = sample;
}



// ── GPIO / I2C for accelerometer ──────────────────────────────────────────
typedef struct {
    volatile unsigned int DATA;
    volatile unsigned int DDR;
} GPIO_t;
#define GPIO_BASE     ((GPIO_t *)0xFF200060)
#define SCL_PIN       0
#define SDA_PIN       1
#define MPU_ADDR      0x68
#define REG_PWR_MGMT  0x6B
#define REG_ACCEL_X_H 0x3B
#define TILT_THRESHOLD 3000   // tune this — lower = more sensitive

// How many main-loop iterations to wait before accepting another accel move
// Prevents the ball from flying across the board on one tilt
#define ACCEL_MOVE_COOLDOWN 4000
static int accel_cooldown = 0;


void i2c_delay(void) { volatile int i; for (i = 0; i < 2000; i++); }
void sda_high(GPIO_t *g) { g->DDR  &= ~(1 << SDA_PIN); }
void sda_low (GPIO_t *g) { g->DATA &= ~(1 << SDA_PIN); g->DDR |= (1 << SDA_PIN); }
int  sda_read(GPIO_t *g) { g->DDR  &= ~(1 << SDA_PIN); i2c_delay(); return (g->DATA >> SDA_PIN) & 1; }
void scl_high(GPIO_t *g) { g->DDR  &= ~(1 << SCL_PIN); }
void scl_low (GPIO_t *g) { g->DATA &= ~(1 << SCL_PIN); g->DDR |= (1 << SCL_PIN); }

void i2c_start(GPIO_t *g) {
    sda_high(g); i2c_delay(); scl_high(g); i2c_delay();
    sda_low(g);  i2c_delay(); scl_low(g);  i2c_delay();
}
void i2c_stop(GPIO_t *g) {
    sda_low(g); i2c_delay(); scl_high(g); i2c_delay(); sda_high(g); i2c_delay();
}
int i2c_write_byte(GPIO_t *g, unsigned char byte) {
    for (int i = 7; i >= 0; i--) {
        if ((byte >> i) & 1) sda_high(g); else sda_low(g);
        i2c_delay(); scl_high(g); i2c_delay(); scl_low(g); i2c_delay();
    }
    sda_high(g); i2c_delay(); scl_high(g); i2c_delay();
    int nack = sda_read(g);
    scl_low(g); i2c_delay(); sda_high(g); i2c_delay();
    return nack;
}
unsigned char i2c_read_byte(GPIO_t *g, int send_ack) {
    unsigned char byte = 0;
    sda_high(g);
    for (int i = 7; i >= 0; i--) {
        i2c_delay(); scl_high(g); i2c_delay();
        if (sda_read(g)) byte |= (1 << i);
        scl_low(g);
    }
    if (send_ack) sda_low(g); else sda_high(g);
    i2c_delay(); scl_high(g); i2c_delay();
    scl_low(g); i2c_delay(); sda_high(g); i2c_delay();
    return byte;
}
void mpu_write_reg(GPIO_t *g, unsigned char reg, unsigned char val) {
    i2c_start(g);
    i2c_write_byte(g, MPU_ADDR << 1);
    i2c_write_byte(g, reg);
    i2c_write_byte(g, val);
    i2c_stop(g);
}
void mpu_read_regs(GPIO_t *g, unsigned char reg, unsigned char *buf, int len) {
    i2c_start(g);
    i2c_write_byte(g, MPU_ADDR << 1);
    i2c_write_byte(g, reg);
    i2c_start(g);
    i2c_write_byte(g, (MPU_ADDR << 1) | 1);
    for (int i = 0; i < len; i++)
        buf[i] = i2c_read_byte(g, i < len - 1);
    i2c_stop(g);
}





