// draw the player ball (PINK) or RL agent ball (BLUE)
// pass color==BLACK to erase (draws a black rectangle over the bounding box)
void draw_ball(int x, int y, short color, char tilt) {

    int z = get_z_from_xy(x, y, tilt);
    int cx = projectPoint(x, y, z).x;
    int cy = projectPoint(x, y, z).y;

    // ERASE (robust — no artifacts)
    if (color == BLACK) {
        int r = BALL_SIZE/2 + 2;
        for (int dy = -r; dy <= r; dy++)
            for (int dx = -r; dx <= r; dx++)
                plot_pixel(cx + dx, cy + dy, BLACK);
        return;
    }

    // main ball
    fill_circle(cx, cy, BALL_SIZE/2, color);

    // 3D highlight (top-left)
    fill_circle(cx - 2, cy - 2, BALL_SIZE/6, 0xFFFF);
}

// draw the pulsing target at tile (col, row)
// pulse_frame alternates the outer ring radius and color each agent tick,
// creating a ripple-outward animation without needing a separate timer
// draw the target at tile (col, row)
void draw_target(int col, int row, short color) {

    int x = col_to_px(col);
    int y = row_to_py(row);
    int z = get_z_from_xy(x, y, prev_tilt);

    int cx = projectPoint(x, y, z).x;
    int cy = projectPoint(x, y, z).y;

    // erase
    if (color == BLACK) {
        draw_rect(cx - TILE/2, cy - TILE/2, TILE, TILE, BLACK);
        return;
    }

    // solid turquoise fill
    fill_circle(cx, cy, TILE/2 - 6, COL_TARGET);

    // turquoise ring (same color, clean look)
    draw_circle(cx, cy, TILE/2 - 2, COL_TARGET);
}

// pick a random open tile for the target, avoiding the ball start tile (bc, br)
void spawn_target(int m, int bc, int br) {
    int col, row;
    do {
        col = 1 + rand() % (COLS-2);
        row = 1 + rand() % (ROWS-2);
    } while (maps[m][row][col] != 0 || (col==bc && row==br));
    target_col = col;
    target_row = row;
    
    draw_target(target_col, target_row, COL_TARGET);

    // values for dfs only at spawn
    if (game_mode == MODE_DFS) {
        int ac = px_to_col(agent_px);
        int ar = py_to_row(agent_py);
        compute_dfs_path(m, ac, ar);
    }
}




// Make the following a different file for spawn_teleport stuff
// ----------------------------------
// ── Warp holes ────────────────────────────────────────────────────────────
#define PORTAL_RADIUS  6
#define PORTAL_LIFETIME 300   // in phys_ticks (~3 seconds at tick>=500)

//for sprite drawing
int portal_frame = 0;
int portal_frame_timer = 0;
#define PORTAL_ANIM_SPEED 4   // ticks per frame, tune this to speed up/slow down

typedef struct {
    int col_a, row_a;   // entry hole
    int col_b, row_b;   // exit hole
    int active;
    int life;           // countdown to despawn
} Portal;

Portal portal = {0};
int portal_spawn_timer = 0;
#define PORTAL_SPAWN_INTERVAL 600  // ticks between spawns


void draw_portal(int col, int row, short color) {
    int x = col_to_px(col);
    int y = row_to_py(row);
    int z = get_z_from_xy(x, y, prev_tilt);
    int cx = projectPoint(x, y, z).x;
    int cy = projectPoint(x, y, z).y;

    if (color == BLACK) {
        // erase: black out the sprite area
        int x0 = cx - PORTAL_W / 2;
        int y0 = cy - PORTAL_H / 2;
        for (int dy = 0; dy < PORTAL_H; dy++)
            for (int dx = 0; dx < PORTAL_W; dx++)
                plot_pixel(x0 + dx, y0 + dy, BLACK);
        return;
    }

    // draw current animation frame
    unsigned short *frame = teleport_frames[portal_frame];
    int x0 = cx - PORTAL_W / 2;
    int y0 = cy - PORTAL_H / 2;
    for (int dy = 0; dy < PORTAL_H; dy++) {
        for (int dx = 0; dx < PORTAL_W; dx++) {
            unsigned short px_color = frame[dy * PORTAL_W + dx];
            if (px_color != 0x0000)   // skip transparent pixels
                plot_pixel(x0 + dx, y0 + dy, px_color);
        }
    }
}

void draw_portals(void) {
    if (!portal.active) return;
    draw_portal(portal.col_a, portal.row_a, 0x07FF);  // cyan
    draw_portal(portal.col_b, portal.row_b, 0x07FF);  // same color — they're a pair
}

void erase_portals(void) {
    if (!portal.active) return;
    draw_portal(portal.col_a, portal.row_a, BLACK);
    draw_portal(portal.col_b, portal.row_b, BLACK);
}

void spawn_portal(int m, int px, int py) {
    int pcol = px_to_col(px);
    int prow = py_to_row(py);
    int ca, ra, cb, rb;
    do {
        ca = 1 + rand() % (COLS - 2);
        ra = 1 + rand() % (ROWS - 2);
    } while (maps[m][ra][ca] != 0 || (ca == pcol && ra == prow));
    do {
        cb = 1 + rand() % (COLS - 2);
        rb = 1 + rand() % (ROWS - 2);
    } while (maps[m][rb][cb] != 0 || (cb == ca && rb == ra) || (cb == pcol && rb == prow));

    portal.col_a = ca; portal.row_a = ra;
    portal.col_b = cb; portal.row_b = rb;
    portal.active = 1;
    portal.life = PORTAL_LIFETIME;
    draw_portals();
}

// Returns 1 if ball center is on a portal tile, sets *dest_col / *dest_row
int check_portal(int px, int py, int *dest_col, int *dest_row) {
    if (!portal.active) return 0;

    // ball 3d bounds
    int pz = get_z_from_xy(px, py, prev_tilt);
    int cx = projectPoint(px, py, pz).x;
    int cy = projectPoint(px, py, pz).y;

    int r = BALL_SIZE / 2;
    int minBallX = cx - r;
    int minBallY = cy - r;
    int maxBallX = cx + r;
    int maxBallY = cy + r;

    // check portal A
    int ax = col_to_px(portal.col_a);
    int ay = row_to_py(portal.row_a);
    int az = get_z_from_xy(ax, ay, prev_tilt);
    int acx = projectPoint(ax, ay, az).x;
    int acy = projectPoint(ax, ay, az).y;
    int minAX = acx - r, minAY = acy - r;
    int maxAX = acx + r, maxAY = acy + r;

    if (maxBallX >= minAX && minBallX <= maxAX &&
        maxBallY >= minAY && minBallY <= maxAY) {
        trigger_clip(snd_teleport, snd_teleport_len);
        *dest_col = portal.col_b;
        *dest_row = portal.row_b;
        return 1;
    }

    // check portal B
    int bx = col_to_px(portal.col_b);
    int by = row_to_py(portal.row_b);
    int bz = get_z_from_xy(bx, by, prev_tilt);
    int bcx = projectPoint(bx, by, bz).x;
    int bcy = projectPoint(bx, by, bz).y;
    int minBX = bcx - r, minBY = bcy - r;
    int maxBX = bcx + r, maxBY = bcy + r;

    if (maxBallX >= minBX && minBallX <= maxBX &&
        maxBallY >= minBY && minBallY <= maxBY) {
        trigger_clip(snd_teleport, snd_teleport_len);
        *dest_col = portal.col_a;
        *dest_row = portal.row_a;
        return 1;
    }

    return 0;
}

